    minCost[0] = 0;

    while (!pq.empty()) {
        long long minEdge = pq.top().first;
        int node = pq.top().second;
        pq.pop();

        if (node == n - 1) {
            return minEdge;
        }

        for (auto& [neighbor, cost] : adj[node]) {
            if (online[neighbor]) {
                long long newMin = min(minEdge, cost);
                long long totalCost = minCost[node] + cost;

                if (totalCost <= k && newMin > minCost[neighbor]) {
                    minCost[neighbor] = newMin;
                    pq.push({newMin, neighbor});
                }
            }
        }
    }

    return -1;
}

